class LegacyAuth:
    def __init__(self, secret):
        self.secret = secret
        self.sessions = {}

    def login(self, user, password):
        if self._check(user, password):
            token = self._make_token(user)
            self.sessions[token] = user
            return token
        return None

    def _check(self, user, password):
        import hashlib
        digest = hashlib.md5(password.encode()).hexdigest()
        return self._lookup(user) == digest

    def _make_token(self, user):
        import uuid
        return uuid.uuid4().hex

    def _lookup(self, user):
        return self.users.get(user)

    def logout(self, token):
        self.sessions.pop(token, None)

    def is_valid(self, token):
        return token in self.sessions

    def all_sessions(self):
        return list(self.sessions.keys())

    def revoke_all(self):
        self.sessions.clear()

    def set_secret(self, secret):
        self.secret = secret

    def rotate_token(self, old_token):
        user = self.sessions.pop(old_token, None)
        if user is None:
            return None
        return self._make_token(user)
